<template><div class="auth-page"><el-card class="auth-card"><h2>首次登录修改密码</h2><el-alert title="为保护账号安全，修改临时密码后才能使用系统。" type="warning" :closable="false" />
<el-form label-position="top"><el-form-item label="当前临时密码"><el-input v-model="form.current" type="password" show-password /></el-form-item><el-form-item label="新密码"><el-input v-model="form.next" type="password" show-password placeholder="至少10位，包含字母和数字" /></el-form-item><el-form-item label="确认新密码"><el-input v-model="form.confirm" type="password" show-password /></el-form-item><el-button class="full" type="primary" :loading="loading" @click="submit">修改并重新登录</el-button></el-form></el-card></div></template>
<script setup lang="ts">import{reactive,ref}from'vue';import{useRouter}from'vue-router';import{ElMessage}from'element-plus';import{changePassword}from'@/api';const router=useRouter(),loading=ref(false),form=reactive({current:'',next:'',confirm:''});async function submit(){if(form.next!==form.confirm)return ElMessage.warning('两次新密码不一致');loading.value=true;try{await changePassword(form.current,form.next);localStorage.removeItem('supervision_token');localStorage.removeItem('supervision_user');ElMessage.success('密码已修改，请重新登录');router.replace('/login')}catch(e:any){ElMessage.error(e?.response?.data?.message||'修改失败')}finally{loading.value=false}}</script>
<style scoped>.auth-page{height:100vh;display:flex;align-items:center;justify-content:center;background:#f3f6fb}.auth-card{width:420px}.auth-card h2{text-align:center}.auth-card .el-alert{margin-bottom:20px}.full{width:100%}</style>